import { n as gatewayInstallErrorHint, t as buildGatewayInstallPlan } from "./daemon-install-helpers-DuZWKez3.js";
import "./runtime-guard-BwU7cq4B.js";
import { r as isGatewayDaemonRuntime, t as DEFAULT_GATEWAY_DAEMON_RUNTIME } from "./daemon-runtime-B4ocYoH1.js";
import { r as isSystemdUserServiceAvailable } from "./systemd-CZE67kXo.js";
import { t as resolveGatewayService } from "./service-B8NMhOHq.js";
